class Solution:
    def fractionToDecimal(self, numerator, denominator):
        if numerator == 0:
            return '0'
        sign = '-' if (numerator < 0) != (denominator < 0) else ''
        n = abs(numerator)
        d = abs(denominator)
        integer = n // d
        rem = n % d
        if rem == 0:
            return sign + str(integer)
        digits = []
        seen = {}
        idx = 0
        repeat_start = -1
        while rem != 0:
            if rem in seen:
                repeat_start = seen[rem]
                break
            seen[rem] = idx
            rem *= 10
            digits.append(str(rem // d))
            rem = rem % d
            idx += 1
        if repeat_start == -1:
            frac = ''.join(digits)
        else:
            frac = ''.join(digits[:repeat_start]) + '(' + ''.join(digits[repeat_start:]) + ')'
        return sign + str(integer) + '.' + frac

