class Solution:
    def fractionToDecimal(self, numerator, denominator):
        if numerator == 0:
            return '0'
        sign = '-' if (numerator < 0) != (denominator < 0) else ''
        n = abs(numerator)
        d = abs(denominator)
        res = [sign, str(n // d)]
        rem = n % d
        if rem == 0:
            return ''.join(res)
        res.append('.')
        seen = {}
        frac = []
        while rem != 0 and rem not in seen:
            seen[rem] = len(frac)
            rem *= 10
            frac.append(str(rem // d))
            rem %= d
        if rem == 0:
            res.append(''.join(frac))
        else:
            pos = seen[rem]
            res.append(''.join(frac[:pos]))
            res.append('(' + ''.join(frac[pos:]) + ')')
        return ''.join(res)

