var fractionToDecimal = function(numerator, denominator) {
    if (numerator === 0) return '0';
    const sign = (numerator < 0) !== (denominator < 0) ? '-' : '';
    let n = Math.abs(numerator);
    let d = Math.abs(denominator);
    const res = [sign, String(Math.trunc(n / d))];
    let rem = n % d;
    if (rem === 0) return res.join('');
    res.push('.');
    const seen = new Map();
    const frac = [];
    while (rem !== 0 && !seen.has(rem)) {
        seen.set(rem, frac.length);
        rem *= 10;
        frac.push(String(Math.trunc(rem / d)));
        rem = rem % d;
    }
    if (rem === 0) {
        res.push(frac.join(''));
    } else {
        const pos = seen.get(rem);
        res.push(frac.slice(0, pos).join(''));
        res.push('(' + frac.slice(pos).join('') + ')');
    }
    return res.join('');
};
